import{_ as e,c as t,o,ag as i}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"installation.md","filePath":"installation.md","lastUpdated":1770142340000}'),n={name:"installation.md"};function r(l,a,s,c,d,p){return o(),t("div",null,a[0]||(a[0]=[i('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>Welcome to CampaignBay! This guide will walk you through installing both the free CampaignBay plugin and the optional CampaignBayPro extension.</p><div class="info custom-block"><p class="custom-block-title">Documentation Version</p><p>This documentation is valid for <strong>CampaignBay 1.1.1</strong> or higher and <strong>CampaignBayPro 1.0.0</strong> and higher.</p></div><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Before you begin, please ensure your WordPress environment meets the following minimum requirements:</p><ul><li><strong>WordPress:</strong> Version 5.8 or higher</li><li><strong>PHP:</strong> Version 7.0 or higher</li><li><strong>WooCommerce:</strong> The WooCommerce plugin must be installed and activated.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you are unsure about any of these requirements, please contact your hosting provider for assistance.</p></div><h2 id="installing-campaignbay-free" tabindex="-1">Installing CampaignBay (Free) <a class="header-anchor" href="#installing-campaignbay-free" aria-label="Permalink to &quot;Installing CampaignBay (Free)&quot;">​</a></h2><p>The free version of CampaignBay is available on WordPress.org and can be installed directly from your dashboard.</p><h3 id="option-1-install-from-wordpress-dashboard-recommended" tabindex="-1">Option 1: Install from WordPress Dashboard (Recommended) <a class="header-anchor" href="#option-1-install-from-wordpress-dashboard-recommended" aria-label="Permalink to &quot;Option 1: Install from WordPress Dashboard (Recommended)&quot;">​</a></h3><ol><li>Log in to your WordPress admin dashboard.</li><li>Navigate to <strong>Plugins → Add New</strong>.</li><li>In the search field, type <strong>&quot;CampaignBay&quot;</strong> and press Enter.</li><li>Find CampaignBay in the search results and click <strong>Install Now</strong>.</li><li>After installation completes, click <strong>Activate</strong>.</li></ol><h3 id="option-2-manual-upload-via-zip-file" tabindex="-1">Option 2: Manual Upload via .zip File <a class="header-anchor" href="#option-2-manual-upload-via-zip-file" aria-label="Permalink to &quot;Option 2: Manual Upload via .zip File&quot;">​</a></h3><p>If you have the plugin&#39;s <code>.zip</code> file:</p><ol><li>Log in to your WordPress admin dashboard.</li><li>Navigate to <strong>Plugins → Add New</strong>.</li><li>Click the <strong>Upload Plugin</strong> button at the top of the screen.</li><li>Click <strong>Choose File</strong> and select the <code>campaignbay.zip</code> file from your computer.</li><li>Click <strong>Install Now</strong>.</li><li>Once complete, click <strong>Activate Plugin</strong>.</li></ol><h3 id="verify-the-installation" tabindex="-1">Verify the Installation <a class="header-anchor" href="#verify-the-installation" aria-label="Permalink to &quot;Verify the Installation&quot;">​</a></h3><p>After activation, you should see a &quot;Plugin activated&quot; confirmation message. Look for the new <strong>&quot;CampaignBay&quot;</strong> menu item in your WordPress admin sidebar.</p><hr><h2 id="installing-campaignbaypro" tabindex="-1">Installing CampaignBayPro <a class="header-anchor" href="#installing-campaignbaypro" aria-label="Permalink to &quot;Installing CampaignBayPro&quot;">​</a></h2><p>CampaignBayPro is a premium extension that adds advanced features to the free plugin. <a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer"><strong>Purchase CampaignBayPro</strong></a> to unlock BOGO Advanced, Product In Cart discounts, and Advanced Conditions.</p><div class="warning custom-block"><p class="custom-block-title">Important</p><p>You must install and activate the free CampaignBay plugin <strong>before</strong> installing CampaignBayPro.</p></div><h3 id="step-1-install-the-free-plugin-first" tabindex="-1">Step 1: Install the Free Plugin First <a class="header-anchor" href="#step-1-install-the-free-plugin-first" aria-label="Permalink to &quot;Step 1: Install the Free Plugin First&quot;">​</a></h3><p>If you haven&#39;t already, follow the instructions above to install and activate the free CampaignBay plugin.</p><h3 id="step-2-download-campaignbaypro" tabindex="-1">Step 2: Download CampaignBayPro <a class="header-anchor" href="#step-2-download-campaignbaypro" aria-label="Permalink to &quot;Step 2: Download CampaignBayPro&quot;">​</a></h3><p>Download the <code>campaignbaypro.zip</code> file from:</p><ul><li>Your purchase confirmation email, or</li><li>Your account page at <a href="https://wpanchorbay.com" target="_blank" rel="noreferrer">wpanchorbay.com</a></li></ul><h3 id="step-3-upload-and-activate" tabindex="-1">Step 3: Upload and Activate <a class="header-anchor" href="#step-3-upload-and-activate" aria-label="Permalink to &quot;Step 3: Upload and Activate&quot;">​</a></h3><ol><li>Log in to your WordPress admin dashboard.</li><li>Navigate to <strong>Plugins → Add New</strong>.</li><li>Click the <strong>Upload Plugin</strong> button.</li><li>Click <strong>Choose File</strong> and select the <code>campaignbaypro.zip</code> file.</li><li>Click <strong>Install Now</strong>.</li><li>Once complete, click <strong>Activate Plugin</strong>.</li></ol><h3 id="step-4-activate-your-license" tabindex="-1">Step 4: Activate Your License <a class="header-anchor" href="#step-4-activate-your-license" aria-label="Permalink to &quot;Step 4: Activate Your License&quot;">​</a></h3><p>After activating the plugin, you need to activate your license key to unlock Pro features and receive updates.</p><ol><li>Navigate to <strong>CampaignBay → Settings</strong>.</li><li>Click the <strong>Advanced</strong> tab.</li><li>In the <strong>License Key</strong> field, enter the license key from your purchase confirmation.</li><li>Click the <strong>Activate</strong> button.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Your license key was sent to your email address when you purchased CampaignBayPro. If you can&#39;t find it, check your spam folder or visit your account page at <a href="https://wpanchorbay.com" target="_blank" rel="noreferrer">wpanchorbay.com</a>.</p></div><p>Once activated, you&#39;ll see a &quot;License Active&quot; confirmation, and all Pro features will be unlocked.</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="woocommerce-is-not-active" tabindex="-1">WooCommerce is not active <a class="header-anchor" href="#woocommerce-is-not-active" aria-label="Permalink to &quot;WooCommerce is not active&quot;">​</a></h3><p>CampaignBay is an add-on for WooCommerce and cannot run without it. Please ensure WooCommerce is installed and activated before activating CampaignBay.</p><h3 id="campaignbay-is-not-active-pro-only" tabindex="-1">CampaignBay is not active (Pro only) <a class="header-anchor" href="#campaignbay-is-not-active-pro-only" aria-label="Permalink to &quot;CampaignBay is not active (Pro only)&quot;">​</a></h3><p>CampaignBayPro requires the free CampaignBay plugin (version 1.1.1 or higher) to be installed and active. If you see a warning message, please update or activate the free plugin first.</p><h3 id="license-activation-failed-pro-only" tabindex="-1">License activation failed (Pro only) <a class="header-anchor" href="#license-activation-failed-pro-only" aria-label="Permalink to &quot;License activation failed (Pro only)&quot;">​</a></h3><p>If license activation fails:</p><ul><li>Double-check that you&#39;ve entered the license key correctly (no extra spaces).</li><li>Ensure your site has an active internet connection.</li><li>Verify that your license hasn&#39;t exceeded the allowed number of site activations.</li><li>Contact support at <a href="https://wpanchorbay.com/support/" target="_blank" rel="noreferrer">wpanchorbay.com/support/</a> for assistance.</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you&#39;ve successfully installed the plugin, the best place to start is the Dashboard.</p><ul><li><strong><a href="./dashboard.html">Explore the Dashboard →</a></strong></li></ul><p>If you&#39;ve installed CampaignBayPro, check out the Pro-exclusive features:</p><ul><li><strong><a href="./campaigns/bogo-advanced-discounts.html">BOGO Advanced Discounts →</a></strong></li><li><strong><a href="./campaigns/product-in-cart-discounts.html">Product In Cart Discounts →</a></strong></li><li><strong><a href="./core-concepts/conditions.html">Advanced Conditions →</a></strong></li></ul>',47)]))}const g=e(n,[["render",r]]);export{u as __pageData,g as default};
